// 把参考图 URL 列表 + 商品图 + prompt 拼成 Gemini parts 数组
const inputs = $input.first().json;
const refs = JSON.parse(inputs.reference_images);
const productUrl = inputs.product_image_url;
const promptExtra = inputs.prompt_extra;
const numOutputs = parseInt(inputs.num_outputs);

const parts = [];

// 主指令
parts.push({
  text: `Generate ${numOutputs} product detail images in the exact style of the reference images below. The product to feature is shown in the last image. Maintain consistent visual language: same color palette, lighting, composition logic, typography style. Each output should be high resolution, commercial-grade, e-commerce ready. Additional context: ${promptExtra}`
});

// 参考图（最多 13 张，留 1 张给商品图，14 上限）
for (const url of refs.slice(0, 13)) {
  parts.push({ fileData: { mimeType: 'image/png', fileUri: url } });
}

// 商品图（白底）
parts.push({ fileData: { mimeType: 'image/png', fileUri: productUrl } });

return [{
  json: {
    run_id: inputs.run_id,
    cms_callback: inputs.cms_callback,
    lark_webhook: inputs.lark_webhook,
    gemini_api_key: inputs.gemini_api_key,
    num_outputs: numOutputs,
    payload: {
      contents: [{ role: 'user', parts }],
      generationConfig: {
        responseModalities: ['IMAGE'],
        candidateCount: numOutputs,
        imageConfig: { aspectRatio: '1:1' }
      }
    }
  }
}];

// Gemini 返回的 base64 图片解码 + 写入 /data/outputs/images/<run_id>/
// (n8n 容器有 ./data/files 挂载到 /data)
const fs = require('fs');
const path = require('path');
const gem = $input.first().json;
const runId = $('提取参数').first().json.run_id;

const outDir = `/data/images/${runId}`;
fs.mkdirSync(outDir, { recursive: true });

const urls = [];
let i = 0;
for (const cand of (gem.candidates || [])) {
  for (const part of (cand.content?.parts || [])) {
    if (part.inlineData?.data) {
      i += 1;
      const fname = path.join(outDir, `img-${i}.png`);
      fs.writeFileSync(fname, Buffer.from(part.inlineData.data, 'base64'));
      urls.push(fname);
    }
  }
}

return [{
  json: {
    run_id: runId,
    cms_callback: $('提取参数').first().json.cms_callback,
    lark_webhook: $('提取参数').first().json.lark_webhook,
    output_files: urls,
    summary: {
      generated: urls.length,
      cost_usd: (urls.length * 0.045).toFixed(3)
    }
  }
}];

